import { useState, useRef } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { useData } from "../contexts/DataContext";
import { Button } from "../components/ui/button";
import { Dialog, DialogContent } from "../components/ui/dialog";
import { X, CheckCircle2 } from "lucide-react";
import { toast } from "sonner";

export default function UpInvoice() {
  const { id } = useParams();
  const { orders = [], setInvoiceUploaded } = useData();
  const navigate = useNavigate();

  const fileInputRef = useRef(null);

  const order = orders.find((o) => String(o.id) === id);

  const [file, setFile] = useState(null);
  const [dragOver, setDragOver] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [loading, setLoading] = useState(false);

  if (!order) {
    return (
      <div>
        <p className="text-gray-500">Pesanan tidak ditemukan.</p>
        <Button onClick={() => navigate("/status-pengiriman")} className="mt-4">
          Kembali
        </Button>
      </div>
    );
  }

  const handleFile = (f) => {
    if (!f) return;
    const validType = f.type === "application/pdf" || f.type === "image/png";
    if (!validType) {
      toast.error("File harus PDF atau PNG");
      return;
    }
    setFile(f);
  };

  const handleSubmit = async () => {
    if (!file) {
      toast.error("Pilih file terlebih dahulu");
      return;
    }
    try {
      setLoading(true);
      await new Promise((res) => setTimeout(res, 800));
      setInvoiceUploaded(order.id);
      setShowSuccess(true);
    } catch (err) {
      toast.error("Gagal upload invoice");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-[900px]" data-testid="up-invoice-page">
      {/* Breadcrumb */}
      <div className="flex items-center gap-2 text-xs font-semibold mb-4">
        <span
          className="text-gray-400 uppercase tracking-wide cursor-pointer hover:text-gray-600"
          onClick={() => navigate("/status-pengiriman")}
        >
          Status Pesanan
        </span>
        <span className="text-gray-400">›</span>
        <span className="text-[#F59E0B] uppercase tracking-wide">
          Pesanan {order.id}
        </span>
      </div>

      {/* Title */}
      <h1 className="text-3xl font-extrabold text-gray-900">Invoice</h1>
      <h2 className="text-3xl font-extrabold text-[#F59E0B] mt-1">
        #{order.id}
      </h2>

      <p className="text-sm text-gray-500 mt-3 mb-7">
        Kirim invoice ke customer
      </p>

      {/* Card */}
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-8">
        {/* Card Header */}
        <div className="flex items-start justify-between mb-1">
          <div>
            <h3 className="text-base font-bold text-gray-900">Kirim Invoice</h3>
            <p className="text-sm text-gray-400 mt-0.5">
              Tambahkan dokumen disini
            </p>
          </div>
          <button
            onClick={() => navigate(-1)}
            className="text-gray-400 hover:text-gray-600 transition"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Upload Zone */}
        <div
          onClick={() => fileInputRef.current?.click()}
          onDragOver={(e) => {
            e.preventDefault();
            setDragOver(true);
          }}
          onDragLeave={() => setDragOver(false)}
          onDrop={(e) => {
            e.preventDefault();
            setDragOver(false);
            handleFile(e.dataTransfer.files?.[0]);
          }}
          className={`mt-5 border-2 border-dashed rounded-xl p-14 text-center cursor-pointer transition-colors ${
            dragOver
              ? "border-[#F59E0B] bg-[#FEF3C7]/50"
              : "border-[#F59E0B] bg-white"
          }`}
        >
          <div className="flex flex-col items-center gap-3">
            {/* Folder icon matching UI */}
            <div className="relative">
              <svg
                width="52"
                height="52"
                viewBox="0 0 52 52"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
              >
                {/* Folder back */}
                <rect
                  x="4"
                  y="16"
                  width="44"
                  height="30"
                  rx="4"
                  fill="#F59E0B"
                />
                {/* Folder tab */}
                <path
                  d="M4 20C4 17.8 5.8 16 8 16H22L26 12H44C46.2 12 48 13.8 48 16V20H4Z"
                  fill="#D97706"
                />
                {/* Upload arrow circle */}
                <circle cx="26" cy="31" r="9" fill="white" />
                <path
                  d="M26 27L26 35M26 27L23 30M26 27L29 30"
                  stroke="#F59E0B"
                  strokeWidth="2"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </div>

            {file ? (
              <>
                <div className="text-sm font-medium text-gray-700">
                  {file.name}
                </div>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    setFile(null);
                  }}
                  className="text-xs text-red-500 hover:text-red-700"
                >
                  Hapus file
                </button>
              </>
            ) : (
              <>
                <p className="text-sm text-gray-600">
                  Seret file Anda untuk memulai pengunggahan
                </p>
                <p className="text-sm text-gray-400">ATAU</p>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    fileInputRef.current?.click();
                  }}
                  className="border border-[#F59E0B] text-[#F59E0B] text-sm font-medium px-5 py-1.5 rounded-lg hover:bg-[#FEF3C7] transition"
                >
                  Telusuri file
                </button>
              </>
            )}

            <input
              ref={fileInputRef}
              type="file"
              accept=".pdf,.png"
              hidden
              onChange={(e) => handleFile(e.target.files?.[0])}
            />
          </div>
        </div>

        <p className="text-xs text-gray-400 mt-3">
          Hanya mendukung file .pdf, .png.
        </p>

        {/* Actions */}
        <div className="flex justify-end gap-3 mt-6">
          <Button
            variant="outline"
            onClick={() => navigate(-1)}
            className="border border-gray-200 text-gray-700 font-semibold px-6 py-2 rounded-lg hover:bg-gray-50"
          >
            Kembali
          </Button>

          <Button
            onClick={handleSubmit}
            disabled={!file || loading}
            className="bg-[#F59E0B] hover:bg-[#D97706] text-white font-semibold px-8 py-2 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed transition"
          >
            {loading ? "Mengirim..." : "Kirim"}
          </Button>
        </div>
      </div>

      {/* Success Dialog */}
      <Dialog open={showSuccess} onOpenChange={setShowSuccess}>
        <DialogContent className="max-w-md text-center py-12">
          <div className="flex flex-col items-center gap-4">
            <CheckCircle2 className="w-12 h-12 text-emerald-500" />
            <div className="text-lg font-bold">Invoice Berhasil Terkirim</div>
            <Button
              onClick={() => navigate("/status-pengiriman")}
              className="bg-[#F59E0B] hover:bg-[#D97706] text-white font-semibold px-8 py-2 rounded-lg mt-3"
            >
              Selesai
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}
